        font_mono=[gr.themes.GoogleFont("JetBrains Mono"), "monospace"],
    )

    with gr.Blocks(title="DataChef", theme=theme, css=css) as demo:
        with gr.Row(elem_classes=["header-container"]):
            gr.HTML("""
            <div style="display: flex; align-items: center; gap: 12px;">
                <div style="font-size: 1.8rem;">👨‍🍳</div>
                <div>
                    <h1 class="app-title">DataChef</h1>
                    <div class="app-subtitle">Automated Data Processing Plan & Code Generation</div>
                </div>
            </div>
            """)

        with gr.Row():
            # === Left Column: Inputs ===
            with gr.Column(scale=35, elem_classes=["control-panel"]):

                # Model Status
                with gr.Row(elem_classes=["status-bar-compact"]):
                    # 修复：去掉了 container=False
                    status_html = gr.HTML(get_status_text()) 
                    load_model_btn = gr.Button("↻", size="sm", variant="secondary", min_width=30)

                # Task
                gr.HTML('<div class="custom-label">Task Description</div>')
                task_description = gr.Textbox(
                    label=None,
                    show_label=False,
                    lines=3,
                    value=default_task.get("description", ""),
                    elem_classes=["no-label-input"]
                )

                # Benchmark
                gr.HTML('<div class="custom-label">Benchmark Settings</div>')
                with gr.Group():
                    benchmark_name = gr.Textbox(
                        label="Name", 
                        placeholder="Benchmark Name",
                        value=default_benchmark.get("name", ""),
                        container=False, # Textbox 支持 container=False
                        lines=1
                    )
                    benchmark_description = gr.Textbox(
                        label="Desc",
                        placeholder="Benchmark Description", 
                        lines=3,
                        value=default_benchmark.get("description", ""),
                        container=False
                    )

                # Datasets
                gr.HTML('<div class="custom-label">Datasets</div>')
                with gr.Row(elem_id="df-toolbar"):
                    delete_row_btn = gr.Button("🗑️ Delete Row", size="sm", variant="stop")

                dataset_kwargs = dict(
                    headers=["dataset_id"],
                    datatype=["str"],
                    row_count=(1, "dynamic"),
                    col_count=(1, "fixed"),
                    value=default_dataset_rows,
                    interactive=True,
                    label=None,
                    height=200
                )
                dataset_ids = gr.Dataframe(**dataset_kwargs)
                selected_row = gr.State(None)
                dataset_ids.select(_on_df_select, outputs=selected_row)

                # Actions
                # 修复：使用 elem_classes 替代 style
                with gr.Row(elem_classes=["mt-6"]):
                    run_btn = gr.Button("🚀 Generate Plan & Code", variant="primary", size="lg")
                    preview_btn = gr.Button("👀 Preview Data", variant="secondary", size="lg")

            # === Right Column: Outputs ===
            with gr.Column(scale=65):

                # 1. Dataset Preview (Accordion)
                with gr.Accordion("🔍 Dataset Preview (JSON)", open=False):
                    preview_out = gr.Code(label=None, language="json", interactive=False, lines=10)

                # 2. Plan & Code (Side by Side)
                with gr.Row():
                    # Plan Column
                    with gr.Column():
                        gr.HTML('<div class="output-col-header">📄 Plan</div>')
                        plan_out = gr.Markdown(value="")

                    # Code Column
                    with gr.Column():
                        gr.HTML('<div class="output-col-header">🐍 Code</div>')
                        code_out = gr.Code(label=None, language="python", interactive=False, lines=25)

        # --- Logic Binding ---
        preview_btn.click(_preview_dataset, inputs=[dataset_ids], outputs=[preview_out])

        delete_row_btn.click(
            _delete_selected_row,
            inputs=[dataset_ids, selected_row],
            outputs=[dataset_ids],
        )

        run_btn.click(
            lambda: (gr.update(value="Thinking..."), gr.update(value="# Generating...")),
            outputs=[plan_out, code_out]
        ).then(
            _run_plan_and_code,
            inputs=[task_description, benchmark_name, benchmark_description, dataset_ids],
            outputs=[plan_out, code_out],
        )

        load_model_btn.click(_warmup_model, outputs=[]).then(get_status_text, outputs=[status_html])
        demo.load(_warmup_model, outputs=[]).then(get_status_text, outputs=[status_html])

    return demo

